CommonData.BannerCustomCSS:
#onetrust-consent-sdk #onetrust-banner-sdk {
  background-color: #fff;
}
#onetrust-consent-sdk {
  font-family: "NunitoRegular", "Nunito" ;
}

#onetrust-banner-sdk:focus {
  outline: none;
}

#onetrust-consent-sdk button {
  border-radius: 16px;
}

#onetrust-banner-sdk.otFloatingRounded {
  display: flex;
  margin: auto;
  max-width: 598px;
  width: 598px;
  height: 219px;
  left: auto;
  right: 10%;
  opacity: 1;
  border-radius: 16px;
  padding: 32px !important;
  box-sizing: border-box;
}

#onetrust-banner-sdk.otFloatingRounded:focus {
  border: none !important;
}


#onetrust-banner-sdk #onetrust-policy {
  width: 100%;
  margin-top: 0;
}

#onetrust-consent-sdk #onetrust-policy-text,
#onetrust-consent-sdk #onetrust-banner-sdk a[href] { 
  position: relative;
  margin-top: 30px;
  font-size: 14px !important;
  line-height: 18px !important; 
  padding: 0;
  width: auto;
  color: #333333 !important;
}

#onetrust-consent-sdk #onetrust-policy-text::before {
  content: "\01F36A  Configuraçőes de Cookies";
  font-family: "NunitoBold", "Arial Bold" !important;
  font-size: 16px !important;
  font-weight: bolder;
  position: absolute;
  top: -30px;
}

#onetrust-consent-sdk #onetrust-banner-sdk a[href] { 
  font-style: ;
}

#onetrust-banner-sdk .ot-sdk-row {
  display: flex;
  flex-direction: column !important;
  justify-content: space-between;
  height: 100%;
}

#onetrust-banner-sdk #onetrust-group-container {
  height: 130px;
}

#onetrust-banner-sdk #onetrust-button-group-parent {
  height: fit-content;
  min-width: 100% !important;
  margin-left: 0px;
  display: flex;
  align-items: flex-start !important;
  padding: 0 !important;
}

#onetrust-banner-sdk #onetrust-button-group {
  display: flex;
  flex-direction: row-reverse;
  justify-content: space-between;
  float: none;
  width: auto;
  height: 40px;
  bottom: 10px;
}

#onetrust-consent-sdk #onetrust-pc-btn-handler {
  margin: 0 !important;
  padding: 0;
  min-width: auto;
  width: fit-content !important;
  background-color: transparent;
  color: #333333;
  border: none;
  margin-right: 0;
  font-size: 14px !important;
  font-weight: normal;
  border-bottom: 1px solid;
  border-radius: 0;
  height: 23px !important;
  margin-top: 8px !important;
}

#onetrust-consent-sdk #onetrust-accept-btn-handler,
#onetrust-consent-sdk #onetrust-reject-all-handler {
  margin-bottom: 0;
  min-width: auto;
  font-size: 14px !important;
  line-height: 18px;
  font-weight: bold;
  width: 83px !important;
  height: 40px !important;
  border-radius: 16px;
  margin-left: 0;
  padding: 10px;
}

#onetrust-consent-sdk #onetrust-accept-btn-handler:hover,
#onetrust-consent-sdk #onetrust-reject-all-handler:hover {
  color: #fff;
  background-color: #000;
  border-color: #000;
}

#onetrust-consent-sdk #onetrust-reject-all-handler {
  border: 1px solid #000000;
  width: 125px !important;
}
#onetrust-consent-sdk #onetrust-accept-btn-handler {
  border-color: #FF7020;
  background-color: #FF7020;
}


#onetrust-banner-sdk .ot-sdk-twelve.ot-sdk-columns {
  min-width: 100%;
  width: auto;
}

#onetrust-banner-sdk .ot-sdk-columns {
  width: auto;
}

#onetrust-pc-sdk button {
  border-radius: 16px;
  height: fit-content;
  font-size: 16px;
  color: #000 !important;
}

#onetrust-pc-sdk #accept-recommended-btn-handler,
#onetrust-pc-sdk .save-preference-btn-handler,
#onetrust-pc-sdk #accept-recommended-btn-handler:focus,
#onetrust-pc-sdk .save-preference-btn-handler:focus {
  background-color: #FF7020 !important;
  border-color: #FF7020 !important;
  font-weight: initial !important;
  font-size: 14px !important;
  color: #000 !important;
  outline: none !important;
  letter-spacing: normal;
  opacity: 1 !important;
}

#onetrust-pc-sdk #accept-recommended-btn-handler:hover,
#onetrust-pc-sdk .save-preference-btn-handler:hover {
  color: #fff !important;
  background-color: #000 !important;
  border-color: #000 !important;
  opacity: 0.8 !important;
}

#onetrust-pc-sdk #close-pc-btn-handler.ot-close-icon {
  border: 1px solid #000;
  border-radius: 50%;
}

#onetrust-consent-sdk #onetrust-pc-sdk #ot-pc-desc {
  font-size: 14px;
  line-height: 18px;
}

@media only screen and (max-width: 768px) {
  #onetrust-banner-sdk.otFloatingRounded {
    height: 360px !important;
    width: 280px !important;
    max-width: 280px !important;
    padding: 32px 22px 32px 22px !important;
    margin-bottom: 100px;
    left: 0;
    right: 0;
  }
  #onetrust-banner-sdk #onetrust-policy {
    width: 100%;
  }
  #onetrust-banner-sdk #onetrust-button-group {
    width: 100%;
    flex-direction: column;
    margin-top: 80px;
    height: 90px;
  }
  #onetrust-banner-sdk .onetrust-banner-options {
    text-align: left;
  }
  #onetrust-consent-sdk #onetrust-policy-text::before {
    font-size: 15px !important;
    white-space: nowrap !important;
  }

}
